import re
from datetime import datetime, timedelta

# Load the query results
cases_data_path = var_functions.query_db:5
accounts_data = var_functions.query_db:12

# If data is stored as paths, load them
if isinstance(cases_data_path, str):
    with open(cases_data_path, 'r') as f:
        case_records = json.load(f)
else:
    case_records = cases_data_path

if isinstance(accounts_data, str):
    with open(accounts_data, 'r') as f:
        account_records = json.load(f)
else:
    account_records = accounts_data

# Clean ID function (remove leading #)
def clean_id(id_str):
    if isinstance(id_str, str):
        return id_str.lstrip('#')
    return id_str

# Parse date function
def parse_date(date_str):
    if date_str == 'None' or not date_str:
        return None
    try:
        # Handle various date formats
        date_str = str(date_str).strip()
        # Remove fractional seconds with timezone
        if '.' in date_str:
            date_str = date_str.split('.')[0] + date_str.split('.')[1][3:]  # Remove milliseconds and keep timezone
        return datetime.fromisoformat(date_str.replace('Z', '+00:00'))
    except:
        return None

